import json
import os
import re
import struct
from collections import defaultdict, Counter, deque

EPS = 1e-9
ROUND_DP = 6


def sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])

def dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]

def cross(a, b):
    return (
        a[1]*b[2] - a[2]*b[1],
        a[2]*b[0] - a[0]*b[2],
        a[0]*b[1] - a[1]*b[0],
    )

def mag(v):
    return (v[0]*v[0] + v[1]*v[1] + v[2]*v[2]) ** 0.5

def normalize(v):
    m = mag(v)
    if m < EPS:
        return (0.0, 0.0, 0.0)
    return (v[0]/m, v[1]/m, v[2]/m)

def tri_area(v1, v2, v3):
    return 0.5 * mag(cross(sub(v2, v1), sub(v3, v1)))

def rvert(v):
    return tuple(round(x, ROUND_DP) for x in v)

def parse_ascii(path):
    triangles = []
    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                declared = (float(parts[2]), float(parts[3]), float(parts[4]))
            except Exception:
                declared = (0.0, 0.0, 0.0)
            verts = []
            i += 1
            if i < len(lines) and lines[i].strip() == 'outer loop':
                i += 1
                for _ in range(3):
                    if i < len(lines) and lines[i].strip().startswith('vertex'):
                        vp = lines[i].strip().split()
                        verts.append((float(vp[1]), float(vp[2]), float(vp[3])))
                    i += 1
            if len(verts) == 3:
                triangles.append((declared, verts))
            continue
        i += 1
    return triangles

def parse_binary(path):
    triangles = []
    with open(path, 'rb') as fh:
        data = fh.read()
    if len(data) < 84:
        return triangles
    count = struct.unpack('<I', data[80:84])[0]
    expected = 84 + count * 50
    if len(data) < expected:
        return triangles
    off = 84
    for _ in range(count):
        vals = struct.unpack('<12fH', data[off:off+50])
        declared = (vals[0], vals[1], vals[2])
        v1 = (vals[3], vals[4], vals[5])
        v2 = (vals[6], vals[7], vals[8])
        v3 = (vals[9], vals[10], vals[11])
        triangles.append((declared, [v1, v2, v3]))
        off += 50
    return triangles

def load_stl(path):
    with open(path, 'rb') as fh:
        data = fh.read()
    is_binary = False
    if len(data) >= 84:
        count = struct.unpack('<I', data[80:84])[0]
        if 84 + count * 50 == len(data):
            is_binary = True
    if is_binary:
        return parse_binary(path)
    return parse_ascii(path)

def validate(path):
    triangles = load_stl(path)
    if not triangles:
        return False, 'no_valid_faces'

    degenerate = False
    edge_faces = defaultdict(list)
    oriented = defaultdict(list)
    vertex_to_faces = defaultdict(list)
    face_normals = []
    centroids = []
    areas = []

    for fi, (declared, verts) in enumerate(triangles):
        v1, v2, v3 = verts
        n = cross(sub(v2, v1), sub(v3, v1))
        a = 0.5 * mag(n)
        areas.append(a)
        if a < EPS:
            degenerate = True
        face_normals.append(normalize(n))
        centroids.append(((v1[0]+v2[0]+v3[0])/3.0, (v1[1]+v2[1]+v3[1])/3.0, (v1[2]+v2[2]+v3[2])/3.0))
        rv = [rvert(v1), rvert(v2), rvert(v3)]
        for v in rv:
            vertex_to_faces[v].append(fi)
        cyc = [(rv[0], rv[1]), (rv[1], rv[2]), (rv[2], rv[0])]
        for a1, b1 in cyc:
            key = tuple(sorted((a1, b1)))
            edge_faces[key].append(fi)
            oriented[key].append((a1, b1, fi))

    if degenerate:
        return False, 'degenerate_triangle'

    if any(len(fs) != 2 for fs in edge_faces.values()):
        return False, 'open_or_nonmanifold_edges'

    for key, dirs in oriented.items():
        if len(dirs) != 2:
            continue
        (a1, b1, _f1), (a2, b2, _f2) = dirs
        if a1 == a2 and b1 == b2:
            return False, 'inverted_normals'

    adj = defaultdict(list)
    for key, fs in edge_faces.items():
        if len(fs) == 2:
            f1, f2 = fs
            adj[f1].append(f2)
            adj[f2].append(f1)
    seen = set()
    dq = deque([0])
    seen.add(0)
    while dq:
        f = dq.popleft()
        for nb in adj[f]:
            if nb not in seen:
                seen.add(nb)
                dq.append(nb)
    if len(seen) != len(triangles):
        return False, 'disconnected_shells'

    cx = sum(c[0] for c in centroids) / len(centroids)
    cy = sum(c[1] for c in centroids) / len(centroids)
    cz = sum(c[2] for c in centroids) / len(centroids)
    center = (cx, cy, cz)
    outward_votes = 0
    inward_votes = 0
    for c, n in zip(centroids, face_normals):
        if mag(n) < EPS:
            continue
        d = dot(n, sub(c, center))
        if d > 0:
            outward_votes += 1
        elif d < 0:
            inward_votes += 1
    if inward_votes > outward_votes:
        return False, 'inverted_normals'

    return True, None


def main():
    files = sorted([f for f in os.listdir('.') if re.fullmatch(r'supplier_\d{3}\.stl', f)])
    results = []
    for f in files:
        valid, reason = validate(f)
        item = {'file': f, 'valid': valid}
        if not valid:
            item['reason'] = reason
        results.append(item)
    with open('validation_report.json', 'w') as fh:
        json.dump({'results': results}, fh)
    print(json.dumps({'results': results}, indent=2))

if __name__ == '__main__':
    main()

